import {React, useEffect, useState } from 'react';
import Header from "./partials/Header"
import Todo from "./partials/Todo"
import { useNavigate } from "react-router-dom";
import { getToken, getAllTodos } from '../services/api'; 
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
const Homepage = () => {
    const navigation = useNavigate()
    const [todoList, setTodoList] = useState([])

    useEffect(()=>{
        if(!getToken()) {
            navigation("/login")
            return
        }
        fetchTodoList()
        
    }, [navigation])

    const fetchTodoList = async () => {
        try {
            const result = await getAllTodos();
            if (result.success) {
                setTodoList(result.data.data.todos);
                toast.success("Todos Displayed"); // Show success toast
            } else {
                toast.error(result.error || "Please try again."); // Show error toast
                console.error(result.error);
            }
        } catch (error) {
            toast.error("An error occurred while fetching todos."); // Handle unexpected errors
            console.error(error);
        }
    }
    return(
        <div>
            <Header />
            <div className="container">
                 <ToastContainer 
                    position="top-right"
                    autoClose={1500}
                    hideProgressBar={false}
                    newestOnTop={false}
                    closeOnClick
                    rtl={false}
                    pauseOnFocusLoss
                    draggable
                    pauseOnHover/>
                <div className="row justify-content-md-center mt-4">
                    <Todo />
                    <Todo />
                    <Todo />
                    <Todo />   
                </div>
            </div>

        </div>
    )
}

export default Homepage;
